import os
from azure.storage import CloudStorageAccount

ACCOUNT_NAME = "your_account_name"
ACCOUNT_KEY = "your_account_key"
MODEL_PATH = os.getenv("MODEL_PATH")

def main():
    try:
        # Create a blob service client using the account name and key
        blob_service_client = CloudStorageAccount(ACCOUNT_NAME, ACCOUNT_KEY).create_block_blob_service()
        
        # Get a list of all models in the container
        models = []
        for model in blob_service_client.list_blobs("models"):
            if model.name.endswith(".h5"):
                models.append(model)
        
        # Sort the list by last modified date, descending
        models.sort(key=lambda x: x.properties.last_modified, reverse=True)
        
        # Load the latest model version
        latest_version = models[0]
        print("Loading model:", latest_version.name)
        latest_version.download_to_file("latest_model.h5")
    
    except Exception as e:
        print("Error loading model:", e)